using namespace std;

// A function to add spell suggestions to a given word.
void add_sound_suggest(const string& preword) {
    // Check if the word is empty.
    if (preword.empty()) {
        return;
    }

    // Use a hash table to keep track of processed words.
    unordered_set<string> processed_words;

    // Initialize memory for the suggestions.
    string* suggestions = new string[preword.length() + 1];

    // Iterate over each letter in the word.
    for (int i = 0; i < preword.length(); i++) {
        // Check if the current letter is already processed.
        if (processed_words.find(preword.substr(0, i + 1)) != processed_words.end()) {
            continue;
        }

        // Add the current letter to the hash table.
        processed_words.insert(preword.substr(0, i + 1));

        // Add the current letter to the suggestions array.
        suggestions[i] = preword.substr(0, i + 1);
    }

    // Print the suggestions.
    for (int i = 0; i < preword.length(); i++) {
        cout << suggestions[i] << endl;
    }

    // Free the memory allocated for the suggestions.
    delete[] suggestions;
}

int main() {
    // Test the function with some sample words.
    add_sound_suggest("hello");
    add_sound_suggest("world");

    return 0;
}
