}

// Convert a list to a string
char_u *list_join(list_T *list, const char *sep)
{
    char_u *result = NULL;
    listitem_T *item;
    char_u *tmp;

    ga_init2(&result, 1, 100);

    for (item = list->lv_first; item != NULL; item = item->li_next) {
        if (item != list->lv_first) {
            ga_concat(&result, sep);
        }
        tmp = typval2string(item->li_tv);
        ga_concat(&result, tmp);
        vim_free(tmp);
    }

    return result;
}
