void redis_connect(const char* host, int port, int timeout) {
  // Initialize the Redis context
  redisContext* context = redisConnect(host, port);

  // Check for errors
  if (context == NULL || context->err) {
    if (context) {
      printf("Error: %s\n", context->errstr);
      redisFree(context);
    } else {
      printf("Error: Redis connection failed\n");
    }
    return;
  }

  // Set the timeout
  redisSetTimeout(context, timeout);

  // Check for integer overflow
  if (timeout < 0) {
    printf("Error: timeout cannot be negative\n");
    redisFree(context);
    return;
  }

  // Perform heap allocation
  char* hostname = malloc(sizeof(char) * (strlen(host) + 1));
  if (hostname == NULL) {
    printf("Error: Out of memory\n");
    redisFree(context);
    return;
  }
  strcpy(hostname, host);

  // Perform heap allocation
  char* portname = malloc(sizeof(char) * (strlen(port) + 1));
  if (portname == NULL) {
    printf("Error: Out of memory\n");
    redisFree(context);
    return;
  }
  sprintf(portname, "%d", port);

  // Connect to the Redis server
  redisReply* reply = redisCommand(context, "CONNECT %s %s", hostname, portname);

  // Check for errors
  if (reply == NULL || reply->type != REDIS_REPLY_STATUS) {
    printf("Error: Redis connection failed\n");
    redisFree(context);
    free(hostname);
    free(portname);
    return;
  }

  // Print the status message
  printf("Redis connection successful\n");

  // Free the memory
  redisFree(context);
  free(hostname);
  free(portname);
