    if (!cert) {
        fprintf(stderr, "Failed to get peer certificate\n");
        return -1;
    }

    // Set verification parameters
    SSL_set_verify(ssl, SSL_VERIFY_PEER, NULL);
    SSL_CTX_set_verify(SSL_get_SSL_CTX(ssl), SSL_VERIFY_PEER, NULL);
    SSL_CTX_set_cert_verify_callback(SSL_get_SSL_CTX(ssl), NULL, NULL);

    // Perform verification
    ret = SSL_verify_cert_chain(ssl, cert);
    if (ret <= 0) {
        char err[ERR_LEN];
        ERR_error_string_n(ERR_get_error(), err, ERR_LEN);
        fprintf(stderr, "Error in SSL certificate verification: %s\n", err);
        return -1;
    }

    X509_free(cert);
    return 0;
