namespace tensorflow {

Status RaggedTensorToTensor(const RaggedTensor& ragged_tensor,
                             Tensor* tensor) {
  TF_RETURN_IF_ERROR(ragged_tensor.IsValid());
  if (!ragged_tensor.IsDense()) {
    return errors::InvalidArgument("Cannot convert ragged tensor to dense tensor.");
  }
  tensor->Resize(ragged_tensor.shape());
