  struct curl_llist_element *e;
  struct ssl_sessionid *sid;

  if(!our_ssl_session)
    return;

  /* check if we already know this session */
  for(e = list->head; e; e = e->next) {
    sid = e->ptr;
    if(sid->ssl_session == our_ssl_session) {
      /* we already know this session */
      return;
    }
