#include <stdbool.h>
#include <string.h>

#define MAX_ATTRIBUTE_VALUE_LENGTH 256

typedef struct {
    char* value;
    size_t length;
} XmlAttributeValue;

typedef struct {
    char* buffer;
    size_t capacity;
    size_t length;
} XmlAttributeValuePool;

XmlAttributeValue* appendAttributeValue(XmlAttributeValuePool* pool, const char* value) {
    XmlAttributeValue* result = NULL;

    if (pool->length + strlen(value) + 1 <= pool->capacity) {
        result = poolAppendChar(pool, '\"');
        result = poolStoreString(result, value);
        result = poolAppendChar(result, '\"');
    }

    return result;
}

XmlAttributeValuePool* poolAppendChar(XmlAttributeValuePool* pool, char c) {
    if (pool->length < pool->capacity) {
        pool->buffer[pool->length++] = c;
    }
    return pool;
}

XmlAttributeValuePool* poolStoreString(XmlAttributeValuePool* pool, const char* string) {
    size_t length = strlen(string);
    if (pool->length + length <= pool->capacity) {
        memcpy(pool->buffer + pool->length, string, length);
        pool->length += length;
    }
    return pool;
}
