char* FormatLocaleString(const char* format, ...) {
    va_list args;
    va_start(args, format);
    char* str = AcquireString(MAX_PATH_SIZE);
    vsnprintf(str, MAX_PATH_SIZE, format, args);
    va_end(args);
    return str;
}

char* ConcatenateString(char* str1, char* str2) {
    size_t len1 = strlen(str1);
    size_t len2 = strlen(str2);
    char* result = AcquireString(len1 + len2 + 1);
    memcpy(result, str1, len1);
    memcpy(result + len1, str2, len2);
    result[len1 + len2] = '\0';
    return result;
}

char* TraceSVGClippath(const char* path) {
    char* clippath = AcquireString(MAX_PATH_SIZE);
    char* path_str = FormatLocaleString("path=\"%s\"", path);
    clippath = ConcatenateString(clippath, path_str);
