    if (!one_req) {
        SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
        goto end;
    }

    // Get the OCSP response req info
    req_info = OCSP_one_req_get0_req_info(one_req);
    if (!req_info) {
        SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
        goto end;
    }

    // Get the OCSP response req
    req = OCSP_req_get0_req(req_info);
    if (!req) {
        SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
        goto end;
    }

    // Get the OCSP response responder id
    responder_id = OCSP_req_get0_responder_id(req);
    if (!responder_id) {
        SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
        goto end;
    }

    // Get the OCSP response resp data
    resp_data = OCSP_resp_get0_respdata(basic_response);
    if (!resp_data) {
        SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
        goto end;
    }

    // Check the response for the certificate status
    for (i = 0; i < sk_OCSP_SINGLERESP_num(resp_data->responses); i++) {
        OCSP_SINGLERESP *single_resp;
        ASN1_GENERALIZEDTIME *produced_at;
        ASN1_TIME *this_update;
        ASN1_TIME *next_update;
        int cert_status;

        single_resp = sk_OCSP_SINGLERESP_value(resp_data->responses, i);
        if (!single_resp) {
            SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
            goto end;
        }

        // Check the certificate status
        cert_status = OCSP_check_cert_status(ssl, single_resp, cert_id);
        if (cert_status != OCSP_CERT_STATUS_GOOD) {
            SSLfatal(ssl, SSL_AD_BAD_CERTIFICATE,
                     ERR_R_OCSP_LIB_CERT_STATUS);
            goto end;
        }

        // Get the produced at time
        produced_at = OCSP_resp_get0_produced_at(basic_response);
        if (!produced_at) {
            SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
            goto end;
        }

        // Get the this update time
        this_update = OCSP_resp_get0_this_update(basic_response);
        if (!this_update) {
            SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
            goto end;
        }

        // Get the next update time
        next_update = OCSP_resp_get0_next_update(basic_response);
        if (!next_update) {
            SSLfatal(ssl, SSL_AD_INTERNAL_ERROR, ERR_R_MALLOC_FAILURE);
            goto end;
        }

