        if (!OCSP_check_validity(produced_at, this_update, next_update,
                                  OCSP_RESPID_get0_name(responder_id),
                                  OCSP_RESPID_get0_key(responder_id))) {
            SSLfatal(ssl, SSL_AD_BAD_CERTIFICATE,
                     ERR_R_OCSP_LIB_CERT_REVOKED);
            goto end;
        }
    }

    // The certificate is valid
    SSL_set_ocsp_response(ssl, response);

